import React from "react";

const ProjectCard = ({ title, description, imgSrc, link, gradient, shadowColor, textColor }) => {
  return (
    <div
      className="project-card flex w-full flex-row"
      style={{ opacity: 1, transform: "none" }}
    >
      <div className="flex flex-col lg:mx-10 lg:w-full">
        <div
          draggable={false}
          className="relative overflow-hidden rounded-2xl border border-white/15 bg-[#f2f2f20c] p-1.5 shadow-2xl lg:h-[560px] lg:rounded-3xl lg:p-2"
        >
          <div
            className="absolute inset-x-0 top-0 h-px"
            style={{
              background:
                "linear-gradient(90deg, rgba(0, 0, 0, 0) 5%, rgba(255, 255, 255, 0.8) 35%, rgb(255, 255, 255) 50%, rgba(255, 255, 255, 0.8) 65%, rgba(0, 0, 0, 0) 95%)",
            }}
          ></div>

          <div
            className={`group relative flex size-full flex-col items-center justify-between overflow-hidden rounded-xl lg:rounded-2xl bg-linear-to-b from-black/40 to-transparent transition-all duration-300`}
             >
            <div
              className="absolute inset-0 -z-1"
              style={{
                background:
                  gradient ||
                  "linear-gradient(188.62deg, rgb(61, 26, 122) 49.9%, rgb(126, 34, 206) 81.7%, rgb(192, 132, 252) 93.88%, rgb(249, 215, 147) 113.5%)",
              }}
            ></div>

            <div
              className="absolute inset-x-0 top-px z-10 h-[0.8px] opacity-70"
              style={{
                background:
                  "linear-gradient(90deg, rgba(0, 0, 0, 0) 20%, rgb(255, 255, 255) 50%, rgba(0, 0, 0, 0) 80%)",
              }}
            ></div>

            <div
              className={`hidden w-full flex-row items-center justify-between px-12 py-8 lg:flex ${
                textColor || "text-purple-300"
              } z-20`}
            >
              <h3 
                className="max-w-[90%] text-2xl font-bold"
                style={{ fontFamily: '"Outfit", sans-serif' }} 
              >
                {description}
              </h3>
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="24"
                height="24"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                className="lucide lucide-arrow-right size-6"
                aria-hidden="true"
              >
                <path d="M5 12h14"></path>
                <path d="m12 5 7 7-7 7"></path>
              </svg>
            </div>

            <img
              alt={description || title}
              loading="lazy"
              width={1203}
              height={702}
              className={`lg:group-hover:translate-y-10 w-full max-w-[85%] translate-y-5 -rotate-3 rounded-t-lg border-[1.5px] border-white/20 transition-all duration-300 will-change-transform lg:block lg:rotate-0 lg:group-hover:scale-[1.08] lg:group-hover:-rotate-3 ${
                shadowColor || "shadow-[0_0_30px_#7E22CE]"
              }`}
              src={imgSrc}
              style={{ color: "transparent" }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProjectCard;

import { motion } from 'framer-motion';

const Hero = ({setIsPopupOpen}) => {
  return (
   
    <motion.section
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 1 }}
      className="min-h-[calc(100vh-90px)] bg-black text-white flex flex-col justify-center items-center px-6 text-center pt-6"
    >
      <h1 className="text-3xl sm:text-5xl md:text-6xl font-bold leading-snug mb-2">
        I help businesses <br />
        Build Scalable and <em className="mt-4 inline-block bg-gradient-to-b from-zinc-700 via-zinc-200 to-zinc-400 bg-clip-text text-transparent font-[NyghtSerif] text-[60px]">
          Secure digital solutions.
        </em>
      </h1>

      {/* Animated Row: Name + Image */}
      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 1.2, delay: 0.3 }}
        className="flex items-center justify-center gap-3 flex-wrap mt-6"
      >
        <h1 className="text-2xl sm:text-3xl font-semibold">
          Hello, I'm Rohan Ghadage
        </h1>
        <img
          src="/rohan1.png"
          alt="Rohan Ghadage"
          className="w-20 h-12 sm:w-25 sm:h-10 object-cover rounded-[2rem]"
        />
      </motion.div>

      <p className="animated-gradient-text text-3xl sm:text-2xl font-medium mt-2">a Full Stack Developer</p>

      {/* CTA Section */}
      <div className="mt-10 flex flex-col sm:flex-row gap-4 items-center">
        <button 
          onClick={() => setIsPopupOpen(true)}
          className="group border border-white px-6 py-2 rounded-full font-semibold flex items-center gap-3 transition-all duration-300 hover:bg-white"
        >
          <span className="text-white group-hover:text-black transition duration-300">
            Let's Connect
          </span>
          <span className="bg-white text-black rounded-full w-8 h-8 flex items-center justify-center transition duration-300 group-hover:bg-transparent group-hover:text-black border group-hover:border-black ">
            ➜
          </span>
        </button>
        <span className="text-gray-400 text-sm sm:text-base">connect.rohanghadage@gmail.com</span>
      </div>
    </motion.section>

  );
};

export default Hero;

import { motion } from "framer-motion";

const TechIcon = ({ icon, label, color = "#fff" }) => {
  return (
    <motion.div
      className="group relative flex items-center justify-center gap-2 
                 rounded-xl border border-white/20 bg-neutral-900 
                 px-4 py-1.5 text-sm text-white/80 lg:text-base
                 transition transform hover:scale-105"
      tabIndex={0}
      whileInView={{ opacity: 1, y: 0 }}
      initial={{ opacity: 0, y: 20 }}
      transition={{ duration: 0.4 }}
    >
      <span className="text-xl" style={{ color }}>{icon}</span>
      <span>{label}</span>
    </motion.div>
  );
};

export default TechIcon;
